# server.py — instantiated from templates/python-server-stdio.py
from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool, TextContent
import asyncio, json, psycopg

SERVER_NAME = "faion-internal"
SERVER_VERSION = "1.0.0"
app = Server(SERVER_NAME)

@app.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(name="ping", description="Health probe; returns server status and version",
             inputSchema={"type": "object", "properties": {}}),
        Tool(name="weather.get_current", description="Get current weather conditions for a city",
             inputSchema={"type": "object", "required": ["city"],
                          "properties": {"city": {"type": "string"}}}),
        Tool(name="db.run_query", description="Run a read-only SQL SELECT against analytics replica; returns up to 500 rows",
             inputSchema={"type": "object", "required": ["sql"],
                          "properties": {"sql": {"type": "string"}}}),
    ]

def envelope(payload=None, error=None):
    return [TextContent(type="text", text=json.dumps(
        {"server_version": SERVER_VERSION, "payload": payload, "error": error}))]

@app.call_tool()
async def call_tool(name, args):
    if name == "ping":
        return envelope({"status": "ok"})
    if name == "weather.get_current":
        return envelope({"city": args["city"], "temp_c": 22, "cond": "clear"})
    if name == "db.run_query":
        sql = args["sql"].strip().lower()
        if not sql.startswith("select"):
            return envelope(error={"code": "forbidden", "message": "only SELECT allowed", "retryable": False})
        with psycopg.connect("postgresql://analytics-ro/local") as cx:
            rows = cx.execute(args["sql"]).fetchmany(500)
        return envelope({"rows": [list(r) for r in rows]})
    return envelope(error={"code": "unknown_tool", "message": name, "retryable": False})

asyncio.run(stdio_server(lambda r, w: app.run(r, w, app.create_initialization_options())))
